842	// the seeded failoverSpecs and the boot endpoint the UAPI render installs. It constructs the
843	// resolver AT MOST ONCE, and ONLY when some peer carries a hostname endpoint spec — a config with
844	// zero hostname specs never invokes newResolver, so its wiring is provably inert (Q29). A literal
845	// spec is seeded verbatim (byte-for-byte the pre-G5 behaviour); a hostname spec is resolved under
846	// the [dns] per-lookup timeout and family-filtered. A lookup that fails, times out, or yields no
847	// usable record leaves that spec EMPTY — the peer boots endpoint-less and the re-resolution loop
848	// installs it on first success (R70). A resolver that fails to construct is logged and treated as
849	// absent (every hostname spec then boots empty), since re-resolution must never fail bring-up.
850	func resolveBootEndpoints(cfg *config.Config, newResolver resolverFactory, lg log.Logger) bootEndpoints {
851		peers := cfg.WireGuard.Peers
852		b := bootEndpoints{
853			specs:     make([][]failoverSpec, len(peers)),
854			endpoints: make([]bootEndpoint, len(peers)),
